// // This module implements an 8-bit shift register with synchronous reset and parallel load.
// On every positive edge of the clock signal (clk), the shift register (q) is updated.
// If the reset signal (rst) is high, indicating a reset condition, the shift register value (q) is set to 0.
// If the load signal (load) is active, the shift register loads the input value (data_in).
// If the shift enable signal (shift_en) is active and the load signal (load) is inactive, the shift register shifts its content to the right.
module shift_reg_8bit(
    input clk,          // Chip clock signal.
    input rst,          // Synchronous reset signal.
    input shift_en,     // Shift enable signal.
    input load,         // Parallel load signal.
    input [7:0] data_in, // 8-bit parallel input data.

    output reg [7:0] q // 8-bit output of the shift register.
);

always @(posedge clk) begin
    if (rst)
        q <= 8'b00000000; // Reset shift register to 0
    else if (load)
        q <= data_in; // Load parallel input data
    else if (shift_en)
        q <= q << 1; // Shift left
end

endmodule

